export type Conversation = {
	id: string;
	userId?: string;
	title: string;
	createdAt: Date;
	updatedAt: Date;
};

export type ConversationWithMessages = Conversation & {
	message?: Message[];
};

export type Message = {
	id: string;
	conversationId: string;
	role: "system" | "user" | "assistant" | "data";
	content: string;
	createdAt: Date;
};

export interface SerializedConversation
	extends Omit<Conversation, "createdAt" | "updatedAt"> {
	createdAt: string;
	updatedAt: string;
}

export interface SerializedMessage extends Omit<Message, "createdAt"> {
	createdAt: string;
}

import { z } from "zod";

export const createConversationSchema = z.object({
	id: z.string().optional(),
	title: z.string().optional(),
});

export const updateConversationSchema = z.object({
	title: z.string().optional(),
});

export const chatRequestSchema = z.object({
	messages: z.array(
		z.union([
			// Format with content string
			z.object({
				role: z.enum(["system", "user", "assistant", "data"]),
				content: z.string(),
				id: z.string().optional(),
			}),
			// Format with parts array (from UIMessage)
			z.object({
				role: z.enum(["system", "user", "assistant", "data"]),
				parts: z.array(
					z
						.object({
							type: z.string(),
							text: z.string().optional(),
							// Allow other properties that might be present
						})
						.loose(),
				),
				id: z.string().optional(),
				metadata: z.any().optional(),
			}),
		]),
	),
	conversationId: z.string().optional(),
	model: z.string().optional(),
	/**
	 * Description of the current page context, injected into the AI system prompt.
	 * Sent by ChatInterface when a page has registered context via useRegisterPageAIContext.
	 */
	pageContext: z.string().max(16000).optional(),
	/**
	 * Names of client-side tools currently available on the page.
	 * The server includes matching tool schemas in the streamText call.
	 */
	availableTools: z.array(z.string()).optional(),
	/**
	 * The routeName registered by the page via useRegisterPageAIContext.
	 * Cross-validated server-side against each built-in tool's route allowlist
	 * to prevent a page from claiming tools intended for a different route.
	 */
	routeName: z.string().optional(),
});

"use client";

import { useRef, useState, useMemo } from "react";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import { Send, Paperclip, X, Loader2, FileText } from "lucide-react";
import { cn } from "@/lib/utils";
import { toast } from "sonner";
import { usePluginOverrides } from "@btst/stack/context";
import type { AiChatPluginOverrides } from "../overrides";
import { DEFAULT_ALLOWED_FILE_TYPES, FILE_TYPE_MIME_MAP } from "../overrides";
import { AI_CHAT_LOCALIZATION } from "../localization";
import type { FormEvent } from "react";

/** Represents an attached file with metadata */
export interface AttachedFile {
	/** Data URL or uploaded URL */
	url: string;
	/** MIME type of the file */
	mediaType: string;
	/** Original filename */
	filename: string;
}

// Max file size: 10MB
const MAX_FILE_SIZE = 10 * 1024 * 1024;

interface ChatInputProps {
	input?: string;
	handleInputChange: (e: React.ChangeEvent<HTMLTextAreaElement>) => void;
	handleSubmit: (e: FormEvent<HTMLFormElement>, files?: AttachedFile[]) => void;
	isLoading: boolean;
	placeholder?: string;
	variant?: "default" | "compact";
	/** Callback when files are attached (for controlled mode) */
	onFilesAttached?: (files: AttachedFile[]) => void;
	/** Attached files (for controlled mode) */
	attachedFiles?: AttachedFile[];
}

export function ChatInput({
	input = "",
	handleInputChange,
	handleSubmit,
	isLoading,
	placeholder,
	variant = "default",
	onFilesAttached,
	attachedFiles: controlledFiles,
}: ChatInputProps) {
	const {
		uploadFile,
		localization: customLocalization,
		mode,
		allowedFileTypes,
	} = usePluginOverrides<AiChatPluginOverrides, Partial<AiChatPluginOverrides>>(
		"ai-chat",
		{},
	);

	const localization = { ...AI_CHAT_LOCALIZATION, ...customLocalization };

	const fileInputRef = useRef<HTMLInputElement>(null);
	const [internalFiles, setInternalFiles] = useState<AttachedFile[]>([]);
	const [isUploading, setIsUploading] = useState(false);

	// Use controlled files if provided, otherwise use internal state
	const attachedFiles = controlledFiles ?? internalFiles;
	const isControlled = controlledFiles !== undefined;

	// Helper to add a file, using functional update for uncontrolled mode
	const addFile = (file: AttachedFile) => {
		if (isControlled && onFilesAttached) {
			// In controlled mode, parent manages state - pass current + new
			onFilesAttached([...attachedFiles, file]);
		} else {
			// In uncontrolled mode, use functional update to avoid stale closure
			setInternalFiles((prev) => [...prev, file]);
		}
	};

	// Helper to remove a file by index - uses functional update to avoid stale closure
	const removeFileAtIndex = (index: number) => {
		if (isControlled && onFilesAttached) {
			// For controlled mode, we need to compute the new array based on current state
			// The parent should ideally use functional updates too, but we pass the filtered array
			// based on the latest controlledFiles prop. If rapid clicks occur before re-render,
			// this could still be stale - parent component should handle batched updates appropriately.
			onFilesAttached(attachedFiles.filter((_, i) => i !== index));
		} else {
			// Uncontrolled mode: use functional update to ensure we always filter from latest state
			setInternalFiles((prev) => prev.filter((_, i) => i !== index));
		}
	};

	const isCompact = variant === "compact";
	const isPublicMode = mode === "public";

	// Get effective allowed file types (default to all if not specified)
	const effectiveAllowedTypes = allowedFileTypes ?? DEFAULT_ALLOWED_FILE_TYPES;

	// Compute the accept string for the file input
	const acceptString = useMemo(() => {
		if (effectiveAllowedTypes.length === 0) return "";
		const mimeTypes = effectiveAllowedTypes.flatMap(
			(type) => FILE_TYPE_MIME_MAP[type] || [],
		);
		return mimeTypes.join(",");
	}, [effectiveAllowedTypes]);

	// File uploads are disabled in public mode or if no file types are allowed
	const canUploadFiles =
		!isPublicMode &&
		typeof uploadFile === "function" &&
		effectiveAllowedTypes.length > 0;

	const handleKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
		if (e.key === "Enter" && !e.shiftKey) {
			e.preventDefault();
			// Pass files to parent and let parent clear them after processing
			handleSubmit(
				e as unknown as FormEvent<HTMLFormElement>,
				attachedFiles.length > 0 ? attachedFiles : undefined,
			);
			// Clear internal files if not controlled
			if (!controlledFiles) {
				setInternalFiles([]);
			}
		}
	};

	const handleFileUpload = async (
		event: React.ChangeEvent<HTMLInputElement>,
	) => {
		const file = event.target.files?.[0];
		if (!file) return;

		if (file.size > MAX_FILE_SIZE) {
			toast.error(localization.FILE_UPLOAD_ERROR_TOO_LARGE);
			return;
		}

		// Use uploadFile if available, otherwise create data URL
		if (uploadFile) {
			try {
				setIsUploading(true);
				const url = await uploadFile(file);
				addFile({ url, mediaType: file.type, filename: file.name });
				toast.success(localization.FILE_UPLOAD_SUCCESS);
			} catch (error) {
				console.error("Failed to upload file:", error);
				toast.error(localization.FILE_UPLOAD_FAILURE);
			} finally {
				setIsUploading(false);
			}
		} else {
			// Fallback: create data URL
			setIsUploading(true);
			const reader = new FileReader();
			reader.onload = (e) => {
				const dataUrl = e.target?.result as string;
				addFile({ url: dataUrl, mediaType: file.type, filename: file.name });
				setIsUploading(false);
			};
			reader.onerror = () => {
				toast.error(localization.FILE_UPLOAD_FAILURE);
				setIsUploading(false);
			};
			reader.readAsDataURL(file);
		}

		// Reset the input
		if (fileInputRef.current) {
			fileInputRef.current.value = "";
		}
	};

	const removeFile = (index: number) => {
		removeFileAtIndex(index);
	};

	const handleFormSubmit = (e: FormEvent<HTMLFormElement>) => {
		// Pass files to parent and let parent clear them after processing
		handleSubmit(e, attachedFiles.length > 0 ? attachedFiles : undefined);
		// Clear internal files if not controlled
		if (!controlledFiles) {
			setInternalFiles([]);
		}
	};

	// Check if a file is an image based on media type
	const isImageFile = (mediaType: string) => mediaType.startsWith("image/");

	return (
		<form onSubmit={handleFormSubmit} className="space-y-2">
			{/* Attached Files Preview */}
			{attachedFiles.length > 0 && (
				<div className="flex flex-wrap gap-2">
					{attachedFiles.map((file, index) => (
						<div
							key={index}
							className="relative group rounded-lg overflow-hidden border"
						>
							{isImageFile(file.mediaType) ? (
								// Image preview
								<img
									src={file.url}
									alt={file.filename}
									className="h-16 w-16 object-cover"
								/>
							) : (
								// File preview with icon
								<div className="w-32 flex items-center gap-2 p-2 bg-muted">
									<FileText className="h-5 w-5 shrink-0 text-muted-foreground" />
									<span className="text-xs truncate" title={file.filename}>
										{file.filename}
									</span>
								</div>
							)}
							<button
								type="button"
								onClick={() => removeFile(index)}
								className="absolute top-0.5 right-0.5 p-0.5 rounded-full bg-background/80 opacity-0 group-hover:opacity-100 transition-opacity"
							>
								<X className="h-3 w-3" />
							</button>
						</div>
					))}
				</div>
			)}

			{/* Input Area */}
			<div className="relative flex items-center gap-2">
				{/* File Upload Button - hidden in public mode */}
				{canUploadFiles && (
					<>
						<input
							ref={fileInputRef}
							type="file"
							accept={acceptString}
							onChange={handleFileUpload}
							className="hidden"
						/>
						<Button
							type="button"
							variant="ghost"
							size="icon"
							onClick={() => fileInputRef.current?.click()}
							disabled={isLoading || isUploading}
							className={cn("shrink-0", isCompact ? "h-8 w-8" : "h-9 w-9")}
							aria-label={localization.FILE_UPLOAD_BUTTON}
						>
							{isUploading ? (
								<Loader2 className="h-4 w-4 animate-spin" />
							) : (
								<Paperclip className="h-4 w-4" />
							)}
						</Button>
					</>
				)}

				{/* Text Input */}
				<div className="relative flex-1 min-w-0">
					<Textarea
						value={input}
						onChange={handleInputChange}
						onKeyDown={handleKeyDown}
						placeholder={placeholder || localization.CHAT_PLACEHOLDER}
						className={cn(
							"resize-none pr-12 max-w-full",
							isCompact
								? "min-h-[40px] max-h-[120px] py-2"
								: "min-h-[50px] max-h-[200px] py-3",
						)}
						rows={1}
					/>
					<Button
						type="submit"
						size="icon"
						disabled={
							isLoading || (!input?.trim() && attachedFiles.length === 0)
						}
						className={cn(
							"absolute right-2 bottom-2",
							isCompact ? "h-7 w-7" : "h-8 w-8",
						)}
						aria-label={localization.CHAT_SEND_BUTTON}
					>
						<Send className={cn(isCompact ? "h-3.5 w-3.5" : "h-4 w-4")} />
					</Button>
				</div>
			</div>
		</form>
	);
}

"use client";

import { useChat } from "@ai-sdk/react";
import { useEffect, useRef, useState, useMemo, useCallback } from "react";
import { useQueryClient } from "@tanstack/react-query";
import { ChatMessage } from "./chat-message";
import { ChatInput, type AttachedFile } from "./chat-input";
import { StackAttribution } from "@/components/ui/stack-attribution";
import { ScrollArea } from "@/components/ui/scroll-area";
import {
	DefaultChatTransport,
	lastAssistantMessageIsCompleteWithToolCalls,
	type UIMessage,
} from "ai";
import { cn } from "@/lib/utils";
import { usePluginOverrides, useBasePath } from "@btst/stack/context";
import type { AiChatPluginOverrides } from "../overrides";
import { AI_CHAT_LOCALIZATION } from "../localization";
import { createApiClient } from "@btst/stack/plugins/client";
import type { AiChatApiRouter } from "@btst/stack/plugins/ai-chat/api";
import { createAiChatQueryKeys } from "@btst/stack/plugins/ai-chat/api";
import {
	useConversation,
	useConversations,
	type SerializedConversation,
} from "@btst/stack/plugins/ai-chat/client/hooks";
import { usePageAIContext } from "../context/page-ai-context";

interface ChatInterfaceProps {
	apiPath?: string;
	initialMessages?: UIMessage[];
	id?: string;
	/** Variant: 'full' for full-page layout, 'widget' for embedded widget */
	variant?: "full" | "widget";
	className?: string;
	/** Called whenever messages change (for persistence). Only fires in public mode. */
	onMessagesChange?: (messages: UIMessage[]) => void;
}

export function ChatInterface({
	apiPath = "/api/chat",
	initialMessages,
	id,
	variant = "full",
	className,
	onMessagesChange,
}: ChatInterfaceProps) {
	const {
		navigate,
		localization: customLocalization,
		apiBaseURL,
		apiBasePath,
		headers,
		mode,
		showAttribution,
		chatSuggestions,
	} = usePluginOverrides<AiChatPluginOverrides, Partial<AiChatPluginOverrides>>(
		"ai-chat",
		{ showAttribution: true },
	);
	const basePath = useBasePath();
	const isPublicMode = mode === "public";

	// Read page AI context registered by the current page
	const pageAIContext = usePageAIContext();

	const localization = { ...AI_CHAT_LOCALIZATION, ...customLocalization };
	const queryClient = useQueryClient();

	const conversationsListQueryKey = useMemo(() => {
		// In public mode, we don't need conversation queries
		if (isPublicMode) return ["ai-chat", "disabled"];
		const client = createApiClient<AiChatApiRouter>({
			baseURL: apiBaseURL,
			basePath: apiBasePath,
		});
		const queries = createAiChatQueryKeys(client, headers);
		return queries.conversations.list().queryKey;
	}, [apiBaseURL, apiBasePath, headers, isPublicMode]);

	// Track the current conversation ID - initialized from prop, updated after first message
	// In public mode, we don't track conversation IDs
	const [currentConversationId, setCurrentConversationId] = useState<
		string | undefined
	>(isPublicMode ? undefined : id);
	// Track if we've sent the first message on a new chat (to trigger navigation)
	const isFirstMessageSentRef = useRef(false);
	const hasNavigatedRef = useRef(false);

	// Update currentConversationId when id prop changes (e.g., navigating to different conversation)
	useEffect(() => {
		if (!isPublicMode) {
			setCurrentConversationId(id);
			isFirstMessageSentRef.current = false;
			hasNavigatedRef.current = false;
			// Reset edit flag on navigation
			isEditInProgressRef.current = false;
		}
	}, [id, isPublicMode]);

	// Fetch existing conversation messages when id is provided (authenticated mode only)
	const { conversation, isLoading: isLoadingConversation } = useConversation(
		id,
		{ enabled: !!id && !isPublicMode },
	);

	// Fetch conversations list for navigation after first message (authenticated mode only)
	const { conversations } = useConversations({ enabled: !isPublicMode });

	// Use a ref to track the conversation ID for the transport body
	// This ensures the transport always uses the latest value
	// In public mode, always undefined
	const conversationIdRef = useRef<string | undefined>(
		isPublicMode ? undefined : id,
	);
	useEffect(() => {
		if (!isPublicMode) {
			conversationIdRef.current = currentConversationId;
		}
	}, [currentConversationId, isPublicMode]);

	// Ref to track edit operation with messages to use
	const editMessagesRef = useRef<UIMessage[] | null>(null);

	// Flag to prevent load conversation effect from overwriting messages during edit
	const isEditInProgressRef = useRef(false);

	// Track if we've finished initializing messages
	// This prevents onMessagesChange from firing with an empty array before initialMessages are loaded
	// Without this guard, the effect would fire on mount with [], overwriting any saved messages
	const [isMessagesInitialized, setIsMessagesInitialized] = useState(
		() =>
			// Start as initialized if there are no initialMessages to load
			!initialMessages || initialMessages.length === 0,
	);

	// Ref to always have the latest pageAIContext in the transport callback
	// without recreating the transport on every context change
	const pageAIContextRef = useRef(pageAIContext);
	useEffect(() => {
		pageAIContextRef.current = pageAIContext;
	}, [pageAIContext]);

	// Memoize the transport to prevent recreation on every render
	const transport = useMemo(
		() =>
			new DefaultChatTransport({
				api: apiPath,
				// In public mode, don't send conversationId
				body: isPublicMode
					? undefined
					: () => ({ conversationId: conversationIdRef.current }),
				// Handle edit operations and inject page context
				prepareSendMessagesRequest: ({ messages: hookMessages }) => {
					const currentPageContext = pageAIContextRef.current;

					// Build page context fields to include in every request
					const pageContextBody = currentPageContext?.pageDescription
						? {
								pageContext: currentPageContext.pageDescription,
								availableTools: Object.keys(
									currentPageContext.clientTools ?? {},
								),
								routeName: currentPageContext.routeName,
							}
						: {};

					// If we're in an edit operation, use the truncated messages + new user message
					if (editMessagesRef.current !== null) {
						const newUserMessage = hookMessages[hookMessages.length - 1];
						const messagesToSend = [...editMessagesRef.current];
						if (newUserMessage) {
							messagesToSend.push(newUserMessage);
						}
						// Clear the ref after use
						editMessagesRef.current = null;
						return {
							body: {
								messages: messagesToSend,
								conversationId: conversationIdRef.current,
								...pageContextBody,
							},
						};
					}
					// Normal case - use the messages as-is
					return {
						body: {
							messages: hookMessages,
							conversationId: conversationIdRef.current,
							...pageContextBody,
						},
					};
				},
			}),
		[apiPath, isPublicMode],
	);

	// Use a ref so addToolOutput is always current inside the onToolCall closure
	const addToolOutputRef = useRef<
		ReturnType<typeof useChat>["addToolOutput"] | null
	>(null);

	const {
		messages,
		sendMessage,
		status,
		error,
		setMessages,
		regenerate,
		addToolOutput,
	} = useChat({
		transport,
		// Automatically resubmit after all client-side tool results are provided
		sendAutomaticallyWhen: lastAssistantMessageIsCompleteWithToolCalls,
		onToolCall: async ({ toolCall }) => {
			// Dispatch client-side tool calls to the handler registered by the current page.
			// In AI SDK v5, onToolCall returns void — addToolOutput must be called explicitly.
			const toolName = toolCall.toolName;
			const handler = pageAIContextRef.current?.clientTools?.[toolName];
			if (handler) {
				try {
					const result = await handler(toolCall.input);
					// No await — avoids potential deadlocks with sendAutomaticallyWhen
					addToolOutputRef.current?.({
						tool: toolName,
						toolCallId: toolCall.toolCallId,
						output: result,
					});
				} catch (err) {
					addToolOutputRef.current?.({
						tool: toolName,
						toolCallId: toolCall.toolCallId,
						state: "output-error",
						errorText:
							err instanceof Error ? err.message : "Tool execution failed",
					});
				}
			} else {
				// No handler found — this happens when the user navigates away while a
				// tool-call response is streaming and the page context changes. Always
				// call addToolOutput so sendAutomaticallyWhen can unblock; without this
				// the conversation gets permanently stuck waiting for a missing output.
				addToolOutputRef.current?.({
					tool: toolName,
					toolCallId: toolCall.toolCallId,
					state: "output-error",
					errorText: `No client-side handler registered for tool "${toolName}". The page context may have changed while the response was streaming.`,
				});
			}
		},
		onError: (err) => {
			console.error("useChat onError:", err);
			// Reset first-message tracking if the send failed before a conversation was created.
			// Without this, isFirstMessageSentRef stays true and the next successful send
			// skips the "first message" navigation logic, corrupting the conversation flow.
			if (!id && !hasNavigatedRef.current) {
				isFirstMessageSentRef.current = false;
			}
		},
		onFinish: async () => {
			// In public mode, skip all persistence-related operations
			if (isPublicMode) return;

			// Invalidate conversation list to show new/updated conversations
			await queryClient.invalidateQueries({
				queryKey: conversationsListQueryKey,
			});

			// If this was the first message on a new chat, update the URL without full navigation
			// This avoids losing the in-memory messages during component remount
			if (isFirstMessageSentRef.current && !id && !hasNavigatedRef.current) {
				hasNavigatedRef.current = true;
				// Wait for the invalidation to complete and refetch conversations
				await queryClient.refetchQueries({
					queryKey: conversationsListQueryKey,
				});
				// Get the updated conversations from cache
				const cachedConversations = queryClient.getQueryData<
					SerializedConversation[]
				>(conversationsListQueryKey);
				if (cachedConversations && cachedConversations.length > 0) {
					// The most recently updated conversation should be the one we just created
					const newConversation = cachedConversations[0];
					if (newConversation) {
						// Update our local state
						setCurrentConversationId(newConversation.id);
						conversationIdRef.current = newConversation.id;
						// Only update the URL in full-page mode; in widget mode the chat is
						// embedded in another page and clobbering the URL is disruptive.
						if (variant === "full") {
							const newUrl = `${basePath}/chat/${newConversation.id}`;
							if (typeof window !== "undefined") {
								window.history.replaceState(
									{ ...window.history.state },
									"",
									newUrl,
								);
							}
						}
					}
				}
			}
		},
	});

	// Keep addToolOutputRef in sync so onToolCall always has the latest reference
	useEffect(() => {
		addToolOutputRef.current = addToolOutput;
	}, [addToolOutput]);

	// Load existing conversation messages when navigating to a conversation
	useEffect(() => {
		// Don't overwrite messages if an edit is in progress
		if (isEditInProgressRef.current) {
			return;
		}
		if (
			conversation?.messages &&
			conversation.messages.length > 0 &&
			messages.length === 0
		) {
			// Filter out "data" role messages as UIMessage only accepts "user" | "assistant" | "system"
			const uiMessages: UIMessage[] = conversation.messages
				.filter((m) => m.role !== "data")
				.map((m) => {
					// Try to parse content as JSON parts (new format with images)
					let parts: UIMessage["parts"];
					try {
						const parsed = JSON.parse(m.content);
						if (Array.isArray(parsed)) {
							parts = parsed;
						} else {
							// Fallback: wrap as text
							parts = [{ type: "text" as const, text: m.content }];
						}
					} catch {
						// Not JSON - legacy format, wrap as text
						parts = [{ type: "text" as const, text: m.content }];
					}
					return {
						id: m.id,
						role: m.role as "user" | "assistant" | "system",
						parts,
					};
				});
			setMessages(uiMessages);
		}
	}, [conversation, messages.length, setMessages]);

	// Set initial messages on mount (for SSR hydration)
	useEffect(() => {
		if (
			initialMessages &&
			initialMessages.length > 0 &&
			messages.length === 0
		) {
			setMessages(initialMessages);
			// Mark as initialized - this is batched with setMessages so both take effect in the same render
			setIsMessagesInitialized(true);
		}
	}, [initialMessages, setMessages, messages.length]);

	const [input, setInput] = useState("");
	const [attachedFiles, setAttachedFiles] = useState<AttachedFile[]>([]);
	const scrollRef = useRef<HTMLDivElement>(null);

	// Track whether the user has manually scrolled away from the bottom.
	// When true, auto-scroll is paused so the user can read earlier context.
	const userHasScrolledRef = useRef(false);
	const prevStatusRef = useRef(status);

	// Reset the scroll lock when a new generation starts so auto-scroll
	// resumes for the next assistant response.
	useEffect(() => {
		if (
			status !== prevStatusRef.current &&
			(status === "streaming" || status === "submitted")
		) {
			userHasScrolledRef.current = false;
		}
		prevStatusRef.current = status;
	}, [status]);

	// Attach a scroll listener to detect when the user scrolls away from the bottom.
	useEffect(() => {
		const viewport = scrollRef.current?.querySelector(
			"[data-radix-scroll-area-viewport]",
		);
		if (!viewport) return;

		const handleScroll = () => {
			const { scrollTop, scrollHeight, clientHeight } = viewport;
			const isNearBottom = scrollHeight - scrollTop - clientHeight < 50;
			userHasScrolledRef.current = !isNearBottom;
		};

		viewport.addEventListener("scroll", handleScroll);
		return () => viewport.removeEventListener("scroll", handleScroll);
	}, []);

	// Auto-scroll to bottom when messages change, unless the user has scrolled away
	useEffect(() => {
		if (userHasScrolledRef.current) return;
		if (scrollRef.current) {
			const scrollElement = scrollRef.current.querySelector(
				"[data-radix-scroll-area-viewport]",
			);
			if (scrollElement) {
				scrollElement.scrollTop = scrollElement.scrollHeight;
			}
		}
	}, [messages]);

	// Notify parent when messages change (for persistence in public mode)
	// Only fire after initialization to prevent overwriting saved messages with an empty array
	useEffect(() => {
		if (isPublicMode && onMessagesChange && isMessagesInitialized) {
			onMessagesChange(messages);
		}
	}, [messages, isPublicMode, onMessagesChange, isMessagesInitialized]);

	const handleInputChange = (e: React.ChangeEvent<HTMLTextAreaElement>) => {
		setInput(e.target.value);
	};

	const handleSubmit = async (
		e: React.FormEvent<HTMLFormElement>,
		files?: AttachedFile[],
	) => {
		e.preventDefault();
		const text = input.trim();
		// Allow submit if there's text OR files
		if (!text && (!files || files.length === 0)) return;

		// Track if this is the first message on a new chat (authenticated mode only)
		if (!isPublicMode && !id && messages.length === 0) {
			isFirstMessageSentRef.current = true;
		}

		// Re-enable auto-scroll so the user's own message (and any subsequent
		// error indicator or assistant reply) is scrolled into view.  Without
		// this, if the user had scrolled up earlier, userHasScrolledRef stays
		// true and none of the new content would be auto-scrolled to — and if
		// the request fails before reaching "streaming" status the ref would
		// remain stuck permanently.
		userHasScrolledRef.current = false;

		// Save current values before clearing - we'll restore them if send fails
		const savedInput = input;
		const savedFiles = files ? [...files] : [];

		// Capture the message count before sending so we can restore to this
		// exact point on failure. The SDK may append both a user message and a
		// partial assistant message during streaming — using a fixed snapshot
		// length removes all of them instead of just the last one.
		const messageCountBeforeSend = messages.length;

		// Clear input immediately (optimistically) - the AI SDK renders messages optimistically,
		// so we need to clear the input before the message appears to avoid duplicate text
		setInput("");
		setAttachedFiles([]);

		try {
			// Use AI SDK's file attachment format
			// The SDK automatically converts supported file types (images, text) to the correct format
			if (files && files.length > 0) {
				// Convert AttachedFile[] to FileUIPart[] format expected by AI SDK
				const fileUIParts = files.map((file) => ({
					type: "file" as const,
					mediaType: file.mediaType,
					url: file.url,
					filename: file.filename,
				}));

				await sendMessage({
					text: text || "", // AI SDK requires text, even if empty
					files: fileUIParts,
				});
			} else {
				await sendMessage({ text });
			}
		} catch (error) {
			// Restore input on failure so user can retry
			setInput(savedInput);
			setAttachedFiles(savedFiles);
			// Reset first-message tracking so the next attempt still triggers navigation
			if (isFirstMessageSentRef.current && !hasNavigatedRef.current) {
				isFirstMessageSentRef.current = false;
			}
			// Remove all messages the SDK added after our send attempt (optimistic
			// user message AND any partial assistant message from a mid-stream failure).
			setMessages((prev) => prev.slice(0, messageCountBeforeSend));
			console.error("Error sending message:", error);
		}
	};

	const isLoading = status === "streaming" || status === "submitted";

	// Handler for retrying/regenerating the last AI response
	const handleRetry = useCallback(() => {
		regenerate();
	}, [regenerate]);

	// Pending edit state - stores the text to send after messages are truncated
	const [pendingEdit, setPendingEdit] = useState<{
		text: string;
		expectedLength: number;
	} | null>(null);

	// Effect to send the edited message after React has processed the truncation
	useEffect(() => {
		if (pendingEdit && messages.length === pendingEdit.expectedLength) {
			const textToSend = pendingEdit.text;
			setPendingEdit(null);
			// Clear edit in progress flag - the new message will now be sent
			// and we want subsequent effects to work normally
			isEditInProgressRef.current = false;
			sendMessage({ text: textToSend });
		}
	}, [messages.length, pendingEdit, sendMessage]);

	// Handler for editing a user message - replaces the message and all subsequent messages
	const handleEditMessage = useCallback(
		(messageId: string, newText: string) => {
			const messageIndex = messages.findIndex((m) => m.id === messageId);
			if (messageIndex === -1) return;

			// Get the message to edit
			const messageToEdit = messages[messageIndex];
			if (!messageToEdit || messageToEdit.role !== "user") return;

			// Truncate to BEFORE the edited message (remove it and all subsequent)
			const truncatedMessages = messages.slice(0, messageIndex);

			// Mark edit in progress to prevent load conversation effect from overwriting
			isEditInProgressRef.current = true;

			// Store the truncated messages in the ref for the transport to use
			editMessagesRef.current = truncatedMessages;

			// Set the pending edit - the useEffect will send after truncation is processed
			setPendingEdit({ text: newText, expectedLength: messageIndex });

			// Truncate the messages - React will batch this and the useEffect will fire after
			setMessages(truncatedMessages);
		},
		[messages, setMessages],
	);

	const isWidget = variant === "widget";

	return (
		<>
			<div className="flex-1 overflow-hidden">
				<div
					className={cn(
						"flex flex-col h-full w-full bg-background",
						isWidget && "rounded-xl",
						className,
					)}
					data-testid="chat-interface"
					data-chat-status={status}
				>
					{/* Messages Area */}
					<ScrollArea ref={scrollRef} className="flex-1 h-full">
						<div
							className={cn(
								"flex flex-col p-4",
								isWidget ? "max-w-full" : "max-w-3xl mx-auto w-full",
							)}
						>
							{messages.length === 0 ? (
								<div className="flex flex-col h-full min-h-[300px]">
									<div className="flex-1 flex items-center justify-center text-muted-foreground mb-4">
										<p>{localization.CHAT_EMPTY_STATE}</p>
									</div>
									{(() => {
										// Merge static suggestions from overrides with dynamic ones from page context.
										// Page context suggestions appear first (most relevant to current page).
										const pageSuggestions = pageAIContext?.suggestions ?? [];
										const allSuggestions = [
											...pageSuggestions,
											...(chatSuggestions ?? []),
										];
										return allSuggestions.length > 0 ? (
											<div className="flex flex-wrap justify-center gap-2 pb-4 max-w-md mx-auto">
												{allSuggestions.map((suggestion, index) => (
													<button
														key={index}
														type="button"
														onClick={() => setInput(suggestion)}
														className="px-3 py-2 text-sm rounded-lg border border-border bg-background hover:bg-accent hover:text-accent-foreground transition-colors text-foreground"
													>
														{suggestion}
													</button>
												))}
											</div>
										) : null;
									})()}
								</div>
							) : (
								messages.map((m, index) => (
									<ChatMessage
										key={m.id || `msg-${index}`}
										message={m}
										isStreaming={
											status === "streaming" &&
											m.id === messages[messages.length - 1]?.id &&
											m.role === "assistant"
										}
										variant={isWidget ? "compact" : "default"}
										onRetry={
											// Only show retry on the last assistant message
											m.role === "assistant" && index === messages.length - 1
												? handleRetry
												: undefined
										}
										onEdit={
											// Allow editing user messages
											m.role === "user"
												? (newText) => handleEditMessage(m.id, newText)
												: undefined
										}
										isRetrying={isLoading && m.role === "assistant"}
									/>
								))
							)}
							{isLoading &&
								messages[messages.length - 1]?.role !== "assistant" && (
									<div className="flex items-center gap-2 text-muted-foreground text-sm py-4">
										<div className="animate-pulse">
											{localization.CHAT_LOADING}
										</div>
									</div>
								)}
							{error && (
								<div className="flex items-center gap-2 text-destructive text-sm py-4 px-3 bg-destructive/10 rounded-md">
									<span>{localization.CHAT_ERROR}</span>
								</div>
							)}
						</div>
					</ScrollArea>
				</div>
			</div>
			{/* Input Area */}
			<div
				className={cn(
					"border-t bg-background p-4",
					isWidget ? "px-3 py-3" : "px-4",
				)}
			>
				<div className={cn(!isWidget && "max-w-3xl mx-auto")}>
					<ChatInput
						input={input}
						handleInputChange={handleInputChange}
						handleSubmit={handleSubmit}
						isLoading={isLoading}
						placeholder={localization.CHAT_PLACEHOLDER}
						variant={isWidget ? "compact" : "default"}
						onFilesAttached={setAttachedFiles}
						attachedFiles={attachedFiles}
					/>
					{showAttribution && <StackAttribution />}
				</div>
			</div>
		</>
	);
}

"use client";

import { useState, useCallback } from "react";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import {
	Sheet,
	SheetContent,
	SheetTrigger,
} from "@/components/ui/sheet";
import {
	Menu,
	PanelLeftClose,
	PanelLeft,
	Sparkles,
	Trash2,
	X,
} from "lucide-react";
import { cn } from "@/lib/utils";
import { ChatSidebar } from "./chat-sidebar";
import { ChatInterface } from "./chat-interface";
import type { UIMessage } from "ai";
import { usePageAIContext } from "../context/page-ai-context";

interface ChatLayoutBaseProps {
	/** API base URL */
	apiBaseURL: string;
	/** API base path */
	apiBasePath: string;
	/** Current conversation ID (if viewing existing conversation) */
	conversationId?: string;
	/** Additional class name for the container */
	className?: string;
	/** Whether to show the sidebar */
	showSidebar?: boolean;
	/** Initial messages to populate the chat (useful for localStorage persistence in public mode) */
	initialMessages?: UIMessage[];
	/** Called whenever messages change (for persistence). Only fires in public mode. */
	onMessagesChange?: (messages: UIMessage[]) => void;
}

interface ChatLayoutWidgetProps extends ChatLayoutBaseProps {
	/** Widget mode: compact embeddable panel with a floating trigger button */
	layout: "widget";
	/** Height of the widget panel. Default: `"600px"` */
	widgetHeight?: string | number;
	/** Width of the widget panel. Default: `"380px"` */
	widgetWidth?: string | number;
	/**
	 * Whether the widget panel starts open. Default: `false`.
	 * Set to `true` when embedding inside an already-open container such as a
	 * Next.js intercepting-route modal — the panel will be immediately visible
	 * without the user needing to click the trigger button.
	 */
	defaultOpen?: boolean;
	/**
	 * Whether to render the built-in floating trigger button. Default: `true`.
	 * Set to `false` when you control open/close externally (e.g. a Next.js
	 * parallel-route slot, a custom button, or a `router.back()` dismiss action)
	 * so that the built-in button does not appear alongside your own UI.
	 */
	showTrigger?: boolean;
}

interface ChatLayoutFullProps extends ChatLayoutBaseProps {
	/** Full-page mode with sidebar navigation (default) */
	layout?: "full";
}

/** Props for the ChatLayout component */
export type ChatLayoutProps = ChatLayoutWidgetProps | ChatLayoutFullProps;

/**
 * ChatLayout component that provides a full-page chat experience with sidebar
 * or a compact widget mode for embedding.
 */
export function ChatLayout(props: ChatLayoutProps) {
	const {
		apiBaseURL,
		apiBasePath,
		conversationId,
		layout = "full",
		className,
		showSidebar = true,
		initialMessages,
		onMessagesChange,
	} = props;

	// Widget-specific props — TypeScript narrows props to ChatLayoutWidgetProps here
	const widgetHeight =
		props.layout === "widget" ? (props.widgetHeight ?? "600px") : "600px";
	const widgetWidth =
		props.layout === "widget" ? (props.widgetWidth ?? "380px") : "380px";
	const defaultOpen =
		props.layout === "widget" ? (props.defaultOpen ?? false) : false;
	const showTrigger =
		props.layout === "widget" ? (props.showTrigger ?? true) : true;

	const [sidebarOpen, setSidebarOpen] = useState(true);
	const [mobileSidebarOpen, setMobileSidebarOpen] = useState(false);
	// Key to force ChatInterface remount when starting a new chat
	const [chatResetKey, setChatResetKey] = useState(0);
	// Widget open/closed state — starts with defaultOpen value
	const [widgetOpen, setWidgetOpen] = useState(defaultOpen);
	// Key to force widget ChatInterface remount on clear
	const [widgetResetKey, setWidgetResetKey] = useState(0);
	// Only mount the widget ChatInterface after the widget has been opened at least once.
	// This ensures pageAIContext is already registered before ChatInterface first renders,
	// so suggestion chips and tool hints appear immediately on first open.
	// When defaultOpen is true the widget is pre-opened, so we mark it as ever-opened immediately.
	const [widgetEverOpened, setWidgetEverOpened] = useState(defaultOpen);

	// Read page AI context to show badge in header
	const pageAIContext = usePageAIContext();

	const apiPath = `${apiBaseURL}${apiBasePath}/chat`;

	// Handler for "New chat" button - increments key to force remount
	const handleNewChat = useCallback(() => {
		// Only needed when we're already on the "new chat" route (/chat).
		// If we're on /chat/:id, navigation to /chat will remount ChatLayout/ChatInterface anyway.
		if (!conversationId) {
			setChatResetKey((prev) => prev + 1);
		}
	}, [conversationId]);

	if (layout === "widget") {
		return (
			<div className={cn("flex flex-col items-end gap-3", className)}>
				{/* Chat panel — always mounted to preserve conversation state, hidden when closed */}
				<div
					className={cn(
						"flex flex-col border rounded-xl overflow-hidden bg-background shadow-xl",
						widgetOpen ? "flex" : "hidden",
					)}
					style={{ height: widgetHeight, width: widgetWidth }}
				>
					{/* Widget header with page context badge and action buttons */}
					<div className="flex items-center gap-1.5 px-3 py-1.5 border-b bg-muted/40">
						<Sparkles className="h-3 w-3 text-muted-foreground" />
						{pageAIContext ? (
							<Badge
								variant="secondary"
								className="text-xs"
								data-testid="page-context-badge"
							>
								{pageAIContext.routeName}
							</Badge>
						) : (
							<span className="text-xs text-muted-foreground font-medium">
								AI Chat
							</span>
						)}
						<div className="flex-1" />
						<Button
							variant="ghost"
							size="icon"
							className="h-5 w-5"
							onClick={() => setWidgetResetKey((prev) => prev + 1)}
							aria-label="Clear chat"
							title="Clear chat"
						>
							<Trash2 className="h-3.5 w-3.5" />
						</Button>
						<Button
							variant="ghost"
							size="icon"
							className="h-5 w-5"
							onClick={() => setWidgetOpen(false)}
							aria-label="Close chat"
						>
							<X className="h-3.5 w-3.5" />
						</Button>
					</div>
					{widgetEverOpened && (
						<ChatInterface
							key={`widget-${conversationId ?? "new"}-${widgetResetKey}`}
							apiPath={apiPath}
							id={conversationId}
							variant="widget"
							initialMessages={initialMessages}
							onMessagesChange={onMessagesChange}
						/>
					)}
				</div>

				{/* Trigger button — rendered only when showTrigger is true */}
				{showTrigger && (
					<Button
						size="icon"
						className="h-12 w-12 rounded-full shadow-lg"
						onClick={() => {
							setWidgetOpen((prev) => !prev);
							setWidgetEverOpened(true);
						}}
						aria-label={widgetOpen ? "Close chat" : "Open chat"}
						data-testid="widget-trigger"
					>
						{widgetOpen ? (
							<X className="h-5 w-5" />
						) : (
							<Sparkles className="h-5 w-5" />
						)}
					</Button>
				)}
			</div>
		);
	}

	// Full layout with sidebar
	return (
		<div
			className={cn(
				"flex h-[calc(100vh-4rem)] w-full overflow-hidden",
				className,
			)}
			data-testid="chat-layout"
		>
			{/* Desktop Sidebar */}
			{showSidebar && (
				<div
					className={cn(
						"hidden md:flex transition-all duration-300 ease-in-out",
						sidebarOpen ? "w-72" : "w-0",
					)}
				>
					{sidebarOpen && (
						<ChatSidebar
							currentConversationId={conversationId}
							onNewChat={handleNewChat}
							className="w-72"
						/>
					)}
				</div>
			)}

			{/* Main Chat Area */}
			<div className="flex-1 flex flex-col min-w-0">
				{/* Header */}
				<div className="flex items-center gap-2 p-2 border-b bg-background/95 backdrop-blur supports-backdrop-filter:bg-background/60">
					{/* Mobile menu button */}
					{showSidebar && (
						<Sheet open={mobileSidebarOpen} onOpenChange={setMobileSidebarOpen}>
							<SheetTrigger asChild>
								<Button
									variant="ghost"
									size="icon"
									className="md:hidden"
									aria-label="Open menu"
								>
									<Menu className="h-5 w-5" />
								</Button>
							</SheetTrigger>
							<SheetContent side="left" className="p-0 w-72">
								<ChatSidebar
									currentConversationId={conversationId}
									onNewChat={() => {
										handleNewChat();
										setMobileSidebarOpen(false);
									}}
								/>
							</SheetContent>
						</Sheet>
					)}

					{/* Desktop sidebar toggle */}
					{showSidebar && (
						<Button
							variant="ghost"
							size="icon"
							className="hidden md:flex"
							onClick={() => setSidebarOpen(!sidebarOpen)}
							aria-label={sidebarOpen ? "Close sidebar" : "Open sidebar"}
						>
							{sidebarOpen ? (
								<PanelLeftClose className="h-5 w-5" />
							) : (
								<PanelLeft className="h-5 w-5" />
							)}
						</Button>
					)}

					<div className="flex-1" />

					{/* Page context badge — shown when a page has registered AI context */}
					{pageAIContext && (
						<Badge
							variant="secondary"
							className="text-xs gap-1 mr-2"
							data-testid="page-context-badge"
						>
							<Sparkles className="h-3 w-3" />
							{pageAIContext.routeName}
						</Badge>
					)}
				</div>

				<ChatInterface
					key={`chat-${conversationId ?? "new"}-${chatResetKey}`}
					apiPath={apiPath}
					id={conversationId}
					variant="full"
					initialMessages={initialMessages}
					onMessagesChange={onMessagesChange}
				/>
			</div>
		</div>
	);
}

