}

interface ChatMessageProps {
	message: UIMessage;
	isStreaming?: boolean;
	variant?: "default" | "compact";
	/** Callback when user wants to retry/regenerate an AI response */
	onRetry?: () => void;
	/** Callback when user edits their message - receives the new text */
	onEdit?: (newText: string) => void;
	/** Whether retry is currently in progress */
	isRetrying?: boolean;
}

export function ChatMessage({
	message,
	isStreaming = false,
	variant = "default",
	onRetry,
	onEdit,
	isRetrying = false,
}: ChatMessageProps) {
	const isUser = message.role === "user";

	const {
		Link,
		Image,
		localization: customLocalization,
		toolRenderers,
	} = usePluginOverrides<AiChatPluginOverrides, Partial<AiChatPluginOverrides>>(
		"ai-chat",
		{},
	);

	const localization = { ...AI_CHAT_LOCALIZATION, ...customLocalization };

	// Use provided Image component or fallback to default
	const ImageComponent = Image ?? DefaultImage;

	// State for copy button
	const [copied, setCopied] = useState(false);

	// State for editing user messages
	const [isEditing, setIsEditing] = useState(false);
	const [editText, setEditText] = useState("");
	const editTextareaRef = useRef<HTMLTextAreaElement>(null);

	// Auto-resize textarea when editing
	useEffect(() => {
		if (isEditing && editTextareaRef.current) {
			editTextareaRef.current.style.height = "auto";
			editTextareaRef.current.style.height = `${editTextareaRef.current.scrollHeight}px`;
			editTextareaRef.current.focus();
		}
	}, [isEditing, editText]);

	// Copy message text to clipboard
	const handleCopy = async () => {
		try {
			await navigator.clipboard.writeText(textContent);
			setCopied(true);
			setTimeout(() => setCopied(false), 2000);
		} catch (err) {
			console.error("Failed to copy text:", err);
		}
	};

	// Start editing
	const handleStartEdit = () => {
		setEditText(textContent);
		setIsEditing(true);
	};

	// Cancel editing
	const handleCancelEdit = () => {
		setIsEditing(false);
		setEditText("");
	};

	// Save edited message
	const handleSaveEdit = () => {
		if (editText.trim() && onEdit) {
			onEdit(editText.trim());
			setIsEditing(false);
			setEditText("");
		}
	};

	// Handle keyboard shortcuts in edit mode
	const handleEditKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
		if (e.key === "Enter" && !e.shiftKey) {
			e.preventDefault();
			handleSaveEdit();
		} else if (e.key === "Escape") {
			handleCancelEdit();
		}
	};

	// Extract text content from message parts
	const textContent = useMemo(() => {
		if (message.parts && Array.isArray(message.parts)) {
			return message.parts
				.filter((part: any) => part.type === "text")
				.map((part: any) => part.text)
				.join("");
		}
		return "";
	}, [message.parts]);

	// Extract image parts from message
	const imageParts = useMemo(() => {
		if (message.parts && Array.isArray(message.parts)) {
			return message.parts.filter(
				(part: any) =>
					part.type === "file" && part.mediaType?.startsWith("image/"),
			);
		}
		return [];
	}, [message.parts]);

	// Extract non-image file parts from message (PDFs, text files, etc.)
	const fileParts = useMemo(() => {
		if (message.parts && Array.isArray(message.parts)) {
			return message.parts.filter(
				(part: any) =>
					part.type === "file" && !part.mediaType?.startsWith("image/"),
			);
		}
		return [];
	}, [message.parts]);

	// Extract tool call parts from message (AI SDK v5 format: type is "tool-{toolName}")
	const toolParts = useMemo(() => {
		if (message.parts && Array.isArray(message.parts)) {
			return message.parts.filter((part: any) => isToolUIPart(part));
		}
		return [];
	}, [message.parts]);

	// Use remend to complete partial markdown when streaming
	const displayContent = useMemo(() => {
		if (!textContent) return "";
		if (isStreaming && !isUser) {
			// Complete any unclosed markdown elements during streaming
			return completeMarkdown(textContent);
		}
		return textContent;
	}, [textContent, isStreaming, isUser]);

	const isCompact = variant === "compact";

	return (
		<div
			className={cn(
				"flex gap-3 w-full",
				isCompact ? "mb-3" : "mb-4",
				isUser ? "justify-end" : "justify-start",
			)}
			aria-label={
				isUser
					? localization.A11Y_USER_MESSAGE
					: localization.A11Y_ASSISTANT_MESSAGE
			}
		>
			{/* Assistant Avatar */}
			{!isUser && (
				<div
					className={cn(
						"rounded-full bg-muted flex items-center justify-center shrink-0",
						isCompact ? "w-7 h-7" : "w-8 h-8",
					)}
				>
					<Bot className={cn(isCompact ? "w-4 h-4" : "w-5 h-5")} />
				</div>
			)}

			{/* Message Content with Action Buttons */}
			<div className="flex flex-col gap-1 max-w-[80%] group">
				<div
					className={cn(
						"rounded-lg",
						isCompact ? "px-3 py-2" : "px-4 py-3",
						isUser ? "bg-primary text-primary-foreground" : "bg-muted",
					)}
				>
					{isUser ? (
						// User messages: files + images + text (or edit mode)
						<div className="space-y-2">
							{/* Attached files (non-images) */}
							{fileParts.length > 0 && (
								<div className="flex flex-wrap gap-2">
									{fileParts.map((part: any, index: number) => (
										<a
											key={index}
											href={part.url}
											target="_blank"
											rel="noopener noreferrer"
											className="flex items-center gap-2 px-3 py-2 rounded-md bg-primary-foreground/10 hover:bg-primary-foreground/20 transition-colors"
										>
											<FileText className="h-4 w-4 shrink-0" />
											<span className="text-xs truncate max-w-[150px]">
												{part.filename || "File"}
											</span>
										</a>
									))}
								</div>
							)}
							{/* Attached images */}
							{imageParts.length > 0 && (
								<div className="flex flex-wrap gap-2">
									{imageParts.map((part: any, index: number) => (
										<ClickableImage
											key={index}
											src={part.url}
											alt={part.filename || `Attached image ${index + 1}`}
											width={150}
											height={150}
											className="rounded-md"
											ImageComponent={ImageComponent}
										/>
									))}
								</div>
							)}
							{/* Text content or edit mode */}
							{isEditing ? (
								<div className="space-y-2">
									<textarea
										ref={editTextareaRef}
										value={editText}
										onChange={(e) => setEditText(e.target.value)}
										onKeyDown={handleEditKeyDown}
										className={cn(
											"w-full min-w-[200px] resize-none rounded-md border-0 bg-primary-foreground/10 p-2 text-sm",
											"focus:outline-none focus:ring-1 focus:ring-primary-foreground/30",
											"text-primary-foreground placeholder:text-primary-foreground/50",
										)}
										rows={1}
									/>
									<div className="flex items-center justify-end gap-2">
										<Button
											type="button"
											size="icon-sm"
											variant="ghost"
											onClick={handleCancelEdit}
											className="h-7 w-7 text-primary-foreground hover:bg-primary-foreground/20"
											title={localization.MESSAGE_CANCEL}
										>
											<X className="h-4 w-4" />
										</Button>
										<Button
											type="button"
											size="icon-sm"
											variant="ghost"
											onClick={handleSaveEdit}
											disabled={!editText.trim()}
											className="h-7 w-7 text-primary-foreground hover:bg-primary-foreground/20 disabled:opacity-50"
											title={localization.MESSAGE_SAVE}
										>
											<Send className="h-4 w-4" />
										</Button>
									</div>
								</div>
							) : (
								textContent && (
									<p
										className={cn(
											"whitespace-pre-wrap wrap-break-word",
											isCompact ? "text-sm" : "text-sm",
										)}
									>
										{textContent}
									</p>
								)
							)}
						</div>
					) : (
						// Assistant messages: rendered markdown + files + images + tool calls
						<div className="wrap-break-word space-y-2">
							{/* Any attached files (non-images) */}
							{fileParts.length > 0 && (
								<div className="flex flex-wrap gap-2">
									{fileParts.map((part: any, index: number) => (
										<a
											key={index}
											href={part.url}
											target="_blank"
											rel="noopener noreferrer"
											className="flex items-center gap-2 px-3 py-2 rounded-md bg-muted-foreground/10 hover:bg-muted-foreground/20 transition-colors border"
										>
											<FileText className="h-4 w-4 shrink-0 text-muted-foreground" />
											<span className="text-xs truncate max-w-[150px]">
												{part.filename || "File"}
											</span>
										</a>
									))}
								</div>
							)}
							{/* Any attached/generated images */}
							{imageParts.length > 0 && (
								<div className="flex flex-wrap gap-2">
									{imageParts.map((part: any, index: number) => (
										<ClickableImage
											key={index}
											src={part.url}
											alt={part.filename || `Image ${index + 1}`}
											width={200}
											height={200}
											className="rounded-md"
											ImageComponent={ImageComponent}
										/>
									))}
								</div>
							)}
							{/* Tool calls */}
							{toolParts.length > 0 && (
								<div className="space-y-2">
									{toolParts.map((part: any) => {
										const toolName = getToolName(part);
										const toolCallId = part.toolCallId;
										const state = part.state as ToolCallState;
										const input = part.input;
										const output = part.output;
										const errorText = part.errorText;
										const isLoading =
											state === "input-streaming" ||
											state === "input-available";

										const toolCallProps: ToolCallProps = {
											toolCallId,
											toolName,
											state,
											input,
											output,
											errorText,
											isLoading,
										};

										// Check if there's a custom renderer for this tool
										const CustomRenderer = toolRenderers?.[toolName];
										if (CustomRenderer) {
											return (
												<CustomRenderer key={toolCallId} {...toolCallProps} />
											);
										}

										// Use default tool call display
										return (
											<ToolCallDisplay key={toolCallId} {...toolCallProps} />
										);
									})}
								</div>
							)}
							{/* Text content */}
							{displayContent ? (
								<MarkdownContent
									markdown={displayContent}
									variant="chat"
									LinkComponent={Link ?? DefaultLink}
									ImageComponent={ImageComponent}
								/>
							) : imageParts.length === 0 &&
								fileParts.length === 0 &&
								toolParts.length === 0 ? (
								<span className="text-muted-foreground">...</span>
							) : null}
						</div>
					)}
				</div>

				{/* Action Buttons */}
				{!isStreaming && !isEditing && (
					<div
						className={cn(
							"flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity",
							isUser ? "justify-end" : "justify-start",
						)}
					>
						{isUser ? (
							// User message actions: Edit
							onEdit && (
								<Button
									type="button"
									size="icon-sm"
									variant="ghost"
									onClick={handleStartEdit}
									className="h-7 w-7 bg-transparent text-muted-foreground hover:text-foreground hover:bg-muted/50"
									title={localization.MESSAGE_EDIT}
								>
									<Pencil className="h-3.5 w-3.5" />
								</Button>
							)
						) : (
							// Assistant message actions: Copy and Retry
							<>
								<Button
									type="button"
									size="icon-sm"
									variant="ghost"
									onClick={handleCopy}
									className="h-7 w-7 bg-transparent text-muted-foreground hover:text-foreground hover:bg-muted/50"
									title={
										copied
											? localization.MESSAGE_COPIED
											: localization.MESSAGE_COPY
									}
								>
									{copied ? (
										<Check className="h-3.5 w-3.5" />
									) : (
										<Copy className="h-3.5 w-3.5" />
									)}
								</Button>
								{onRetry && (
									<Button
										type="button"
										size="icon-sm"
										variant="ghost"
										onClick={onRetry}
										disabled={isRetrying}
										className="h-7 w-7 bg-transparent text-muted-foreground hover:text-foreground hover:bg-muted/50 disabled:opacity-50"
										title={localization.MESSAGE_RETRY}
									>
										<RefreshCw
											className={cn(
												"h-3.5 w-3.5",
												isRetrying && "animate-spin",
											)}
										/>
									</Button>
								)}
							</>
						)}
					</div>
				)}
			</div>

			{/* User Avatar */}
			{isUser && (
				<div
					className={cn(
						"rounded-full bg-primary flex items-center justify-center shrink-0 text-primary-foreground",
						isCompact ? "w-7 h-7" : "w-8 h-8",
					)}
				>
					<User className={cn(isCompact ? "w-4 h-4" : "w-5 h-5")} />
				</div>
			)}
		</div>
	);
}

"use client";

import { useState } from "react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { ScrollArea } from "@/components/ui/scroll-area";
import {
	DropdownMenu,
	DropdownMenuContent,
	DropdownMenuItem,
	DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import {
	AlertDialog,
	AlertDialogAction,
	AlertDialogCancel,
	AlertDialogContent,
	AlertDialogDescription,
	AlertDialogFooter,
	AlertDialogHeader,
	AlertDialogTitle,
} from "@/components/ui/alert-dialog";
import {
	Dialog,
	DialogContent,
	DialogFooter,
	DialogHeader,
	DialogTitle,
} from "@/components/ui/dialog";
import {
	MessageSquarePlus,
	MoreHorizontal,
	Pencil,
	Trash2,
	MessageSquare,
} from "lucide-react";
import { cn } from "@/lib/utils";
import { usePluginOverrides, useBasePath } from "@btst/stack/context";
import type { AiChatPluginOverrides } from "../overrides";
import type { SerializedConversation } from "../../types";
import {
	useConversations,
	useRenameConversation,
	useDeleteConversation,
} from "@btst/stack/plugins/ai-chat/client/hooks";
import { AI_CHAT_LOCALIZATION } from "../localization";

interface ChatSidebarProps {
	currentConversationId?: string;
	onNewChat?: () => void;
	className?: string;
}

export function ChatSidebar({
	currentConversationId,
	onNewChat,
	className,
}: ChatSidebarProps) {
	const { navigate, localization: customLocalization } = usePluginOverrides<
		AiChatPluginOverrides,
		Partial<AiChatPluginOverrides>
	>("ai-chat", {});
	const basePath = useBasePath();

	const localization = { ...AI_CHAT_LOCALIZATION, ...customLocalization };

	const { conversations, isLoading } = useConversations();
	const renameMutation = useRenameConversation();
	const deleteMutation = useDeleteConversation();

	const [renameDialogOpen, setRenameDialogOpen] = useState(false);
	const [deleteDialogOpen, setDeleteDialogOpen] = useState(false);
	const [selectedConversation, setSelectedConversation] =
		useState<SerializedConversation | null>(null);
	const [newTitle, setNewTitle] = useState("");

	const handleNewChat = () => {
		// Always use overrides navigation when available, so consumers control routing.
		// Also run onNewChat to support "reset chat" behavior when already on /chat.
		if (navigate) {
			navigate(`${basePath}/chat`);
		}
		if (onNewChat) {
			onNewChat();
		}
	};

	const handleConversationClick = (conversation: SerializedConversation) => {
		if (navigate) {
			navigate(`${basePath}/chat/${conversation.id}`);
		}
	};

	const handleRenameClick = (conversation: SerializedConversation) => {
		setSelectedConversation(conversation);
		setNewTitle(conversation.title);
		setRenameDialogOpen(true);
	};

	const handleDeleteClick = (conversation: SerializedConversation) => {
		setSelectedConversation(conversation);
		setDeleteDialogOpen(true);
	};

	const handleRenameConfirm = async () => {
		if (selectedConversation && newTitle.trim()) {
			await renameMutation.mutateAsync({
				id: selectedConversation.id,
				title: newTitle.trim(),
			});
			setRenameDialogOpen(false);
			setSelectedConversation(null);
			setNewTitle("");
		}
	};

	const handleDeleteConfirm = async () => {
		if (selectedConversation) {
			await deleteMutation.mutateAsync({ id: selectedConversation.id });
			setDeleteDialogOpen(false);
			setSelectedConversation(null);
			// Navigate away if deleted current conversation
			if (selectedConversation.id === currentConversationId && navigate) {
				navigate(`${basePath}/chat`);
			}
		}
	};

	const formatDate = (dateString: string) => {
		const date = new Date(dateString);
		const now = new Date();
		const diffMs = now.getTime() - date.getTime();
		const diffMins = Math.floor(diffMs / 60000);
		const diffHours = Math.floor(diffMs / 3600000);
		const diffDays = Math.floor(diffMs / 86400000);

		if (diffMins < 1) return localization.TIME_JUST_NOW;
		if (diffMins < 60)
			return localization.TIME_MINUTES_AGO.replace("{count}", String(diffMins));
		if (diffHours < 24)
			return localization.TIME_HOURS_AGO.replace("{count}", String(diffHours));
		if (diffDays === 1) return localization.TIME_YESTERDAY;
		if (diffDays < 7)
			return localization.TIME_DAYS_AGO.replace("{count}", String(diffDays));
		return date.toLocaleDateString();
	};

	return (
		<div
			data-testid="chat-sidebar"
			className={cn("flex flex-col h-full bg-muted/30 border-r", className)}
		>
			{/* Header */}
			<div className="p-4 border-b">
				<Button
					onClick={handleNewChat}
					className="w-full justify-start gap-2"
					variant="outline"
				>
					<MessageSquarePlus className="h-4 w-4" />
					{localization.SIDEBAR_NEW_CHAT}
				</Button>
			</div>

			{/* Conversations List */}
			<ScrollArea className="flex-1 [&_[data-slot=scroll-area-viewport]>div]:!block">
				<div className="p-2">
					{isLoading ? (
						<div className="p-4 text-center text-sm text-muted-foreground">
							{localization.CHAT_LOADING}
						</div>
					) : conversations.length === 0 ? (
						<div className="p-4 text-center text-sm text-muted-foreground">
							{localization.SIDEBAR_NO_CONVERSATIONS}
						</div>
					) : (
						<div className="space-y-1">
							{conversations.map((conversation) => (
								<div
									key={conversation.id}
									className={cn(
										"group flex items-center gap-2 rounded-lg px-3 py-2 hover:bg-accent cursor-pointer transition-colors overflow-hidden",
										currentConversationId === conversation.id && "bg-accent",
									)}
								>
									<button
										type="button"
										className="flex-1 flex items-center gap-2 text-left min-w-0 overflow-hidden"
										onClick={() => handleConversationClick(conversation)}
									>
										<MessageSquare className="h-4 w-4 shrink-0 text-muted-foreground" />
										<div className="flex-1 min-w-0 overflow-hidden">
											<p className="text-sm font-medium truncate">
												{conversation.title}
											</p>
											<p className="text-xs text-muted-foreground truncate">
												{formatDate(conversation.updatedAt)}
											</p>
										</div>
									</button>
									<DropdownMenu>
										<DropdownMenuTrigger asChild>
											<Button
												variant="ghost"
												size="icon"
												className="h-8 w-8 opacity-0 group-hover:opacity-100 transition-opacity"
											>
												<MoreHorizontal className="h-4 w-4" />
											</Button>
										</DropdownMenuTrigger>
										<DropdownMenuContent align="end">
											<DropdownMenuItem
												onClick={(e) => {
													e.stopPropagation();
													handleRenameClick(conversation);
												}}
											>
												<Pencil className="h-4 w-4 mr-2" />
												{localization.CONVERSATION_RENAME}
											</DropdownMenuItem>
											<DropdownMenuItem
												onClick={(e) => {
													e.stopPropagation();
													handleDeleteClick(conversation);
												}}
												className="text-destructive focus:text-destructive"
											>
												<Trash2 className="h-4 w-4 mr-2" />
												{localization.CONVERSATION_DELETE}
											</DropdownMenuItem>
										</DropdownMenuContent>
									</DropdownMenu>
								</div>
							))}
						</div>
					)}
				</div>
			</ScrollArea>

			{/* Rename Dialog */}
			<Dialog open={renameDialogOpen} onOpenChange={setRenameDialogOpen}>
				<DialogContent>
					<DialogHeader>
						<DialogTitle>{localization.CONVERSATION_RENAME}</DialogTitle>
					</DialogHeader>
					<Input
						value={newTitle}
						onChange={(e) => setNewTitle(e.target.value)}
						placeholder={localization.CONVERSATION_RENAME_PLACEHOLDER}
						onKeyDown={(e) => {
							if (e.key === "Enter") {
								void handleRenameConfirm();
							}
						}}
					/>
					<DialogFooter>
						<Button
							variant="outline"
							onClick={() => setRenameDialogOpen(false)}
						>
							{localization.CONVERSATION_RENAME_CANCEL}
						</Button>
						<Button
							onClick={handleRenameConfirm}
							disabled={!newTitle.trim() || renameMutation.isPending}
						>
							{localization.CONVERSATION_RENAME_SAVE}
						</Button>
					</DialogFooter>
				</DialogContent>
			</Dialog>

			{/* Delete Confirmation Dialog */}
			<AlertDialog open={deleteDialogOpen} onOpenChange={setDeleteDialogOpen}>
				<AlertDialogContent>
					<AlertDialogHeader>
						<AlertDialogTitle>
							{localization.CONVERSATION_DELETE_CONFIRM_TITLE}
						</AlertDialogTitle>
						<AlertDialogDescription>
							{localization.CONVERSATION_DELETE_CONFIRM_DESCRIPTION}
						</AlertDialogDescription>
					</AlertDialogHeader>
					<AlertDialogFooter>
						<AlertDialogCancel>
							{localization.CONVERSATION_DELETE_CANCEL}
						</AlertDialogCancel>
						<AlertDialogAction
							onClick={handleDeleteConfirm}
							className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
						>
							{localization.CONVERSATION_DELETE_CONFIRM_BUTTON}
						</AlertDialogAction>
					</AlertDialogFooter>
				</AlertDialogContent>
			</AlertDialog>
		</div>
	);
}

"use client";

import { Skeleton } from "@/components/ui/skeleton";

/**
 * Skeleton loading state for the chat page
 */
export function ChatPageSkeleton() {
	return (
		<div className="flex h-[calc(100vh-4rem)] w-full overflow-hidden">
			{/* Sidebar skeleton */}
			<div className="hidden md:flex w-72 flex-col border-r bg-muted/30">
				<div className="p-4 border-b">
					<Skeleton className="h-10 w-full" />
				</div>
				<div className="flex-1 p-2 space-y-2">
					{Array.from({ length: 5 }).map((_, i) => (
						<div key={i} className="flex items-center gap-2 p-3">
							<Skeleton className="h-4 w-4 shrink-0" />
